section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/semantic-tokens-and-modes.json",
  "title": "Semantic Tokens and Modes",
  "type": "object",
  "required": [
    "artefact_id",
    "system_id",
    "semantic_tokens",
    "modes",
    "primitive_bindings",
    "figma_variable_map",
    "fallback_mode",
    "naming_rules",
    "owners",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "system_id": {
      "type": "string",
      "description": "system_id",
      "minLength": 1
    },
    "semantic_tokens": {
      "type": "array",
      "description": "semantic_tokens (array)",
      "minItems": 1
    },
    "modes": {
      "type": "array",
      "description": "modes (array)",
      "minItems": 1
    },
    "primitive_bindings": {
      "type": "array",
      "description": "primitive_bindings (array)",
      "minItems": 1
    },
    "figma_variable_map": {
      "type": "string",
      "description": "figma_variable_map",
      "minLength": 1
    },
    "fallback_mode": {
      "type": "string",
      "description": "fallback_mode",
      "minLength": 1
    },
    "naming_rules": {
      "type": "array",
      "description": "naming_rules (array)",
      "minItems": 1
    },
    "owners": {
      "type": "string",
      "description": "owners",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
